import { useState } from 'react';
import { Button, Container } from 'react-bootstrap';

function FlashcardView({ set, onBack }) {
  const cards = set.cards;
  const [currentIndex, setCurrentIndex] = useState(0);
  const [flipped, setFlipped] = useState(false);
  const [reviewed, setReviewed] = useState(new Set());

  const current = cards[currentIndex];
  const isLast = currentIndex === cards.length - 1;
  const isFirst = currentIndex === 0;
  const reviewedCount = reviewed.size;

  const handleFlip = () => {
    setFlipped((prev) => !prev);
    if (!flipped) {
      setReviewed((prev) => new Set(prev).add(currentIndex));
    }
  };

  const handleNext = () => {
    if (!isLast) {
      setCurrentIndex((prev) => prev + 1);
      setFlipped(false);
    }
  };

  const handlePrev = () => {
    if (!isFirst) {
      setCurrentIndex((prev) => prev - 1);
      setFlipped(false);
    }
  };

  return (
    <Container className="text-center">
      <h4 className="mb-1">{set.name}</h4>
      <div className="d-flex justify-content-between align-items-center mb-3">
        <Button variant="outline-secondary" size="sm" onClick={onBack}>
          ← Back to Sets
        </Button>
        <span className="text-muted">
          Card {currentIndex + 1} of {cards.length} | Reviewed: {reviewedCount}
        </span>
      </div>

      <div
        className={`flashcard ${flipped ? 'flipped' : ''}`}
        onClick={handleFlip}
        role="button"
        tabIndex={0}
        onKeyDown={(e) => { if (e.key === 'Enter' || e.key === ' ') handleFlip(); }}
        aria-label={flipped ? 'Showing answer. Click to see question.' : 'Showing question. Click to reveal answer.'}
      >
        <div className="flashcard-inner">
          <div className="flashcard-front">
            <h4>Question</h4>
            <p className="fs-5">{current.question}</p>
            <small className="text-muted">Click to reveal answer</small>
          </div>
          <div className="flashcard-back">
            <h4>Answer</h4>
            <p className="fs-5">{current.answer}</p>
            <small className="text-muted">Click to see question</small>
          </div>
        </div>
      </div>

      <div className="d-flex justify-content-center gap-3 mt-4">
        <Button variant="outline-primary" onClick={handlePrev} disabled={isFirst}>
          Previous
        </Button>
        <Button variant="primary" onClick={handleNext} disabled={isLast}>
          Next
        </Button>
      </div>

      {reviewedCount === cards.length && (
        <div className="mt-4 alert alert-success">
          🎉 You&apos;ve reviewed all {cards.length} cards!
        </div>
      )}
    </Container>
  );
}

export default FlashcardView;
